module RefModule (
  input [7:0] d,
  input clk,
  input load,
  input clr,
  output reg [7:0] q
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (clr)
      q <= 8'b00000000;
    else if (load)
      q <= d;
  end

endmodule
